__asm__(
".section .text\n"
".globl _start\n"
"_start:\n"
"  la t0, trap_handler\n"
"  csrw mtvec, t0\n"
"  li t0, 0x0c000028\n"
"  li t1, 1\n"
"  sw t1, 0(t0)\n"
"  li t0, 0x0c002000\n"
"  li t1, (1 << 10)\n"
"  sw t1, 0(t0)\n"
"  li t0, 0x0c200000\n"
"  sw zero, 0(t0)\n"
"  li t0, 0x10000001\n"
"  li t1, 1\n"
"  sb t1, 0(t0)\n"
"  li t0, (1 << 11)\n"
"  csrw mie, t0\n"
"  li t0, (1 << 3)\n"
"  csrs mstatus, t0\n"
"  la s0, done\n"
"wait_uart:\n"
"  ld s1, 0(s0)\n"
"  beqz s1, wait_uart\n"
"  li t0, 0x10000000\n"
"  li t1, 'R'\n"
"  sb t1, 0(t0)\n"
"  li a0, 0\n"
"  ebreak\n"
"trap_handler:\n"
"  li t0, 0x0c200004\n"
"  lw t1, 0(t0)\n"
"  li t2, 10\n"
"  bne t1, t2, trap_fail\n"
"  li t3, 0x10000000\n"
"  lbu t4, 0(t3)\n"
"  la t3, count\n"
"  ld t4, 0(t3)\n"
"  addi t4, t4, 1\n"
"  sd t4, 0(t3)\n"
"  li t5, 32\n"
"  bne t4, t5, complete\n"
"  la t3, done\n"
"  li t4, 1\n"
"  sd t4, 0(t3)\n"
"complete:\n"
"  sw t1, 0(t0)\n"
"  mret\n"
"trap_fail:\n"
"  li a0, 2\n"
"  ebreak\n"
".section .bss\n"
".align 3\n"
"done:\n"
"  .dword 0\n"
"count:\n"
"  .dword 0\n"
);
